import {execFileSync} from 'node:child_process';
import fs from 'node:fs';
import os from 'node:os';
import path from 'node:path';
const dir = fs.mkdtempSync(path.join(os.tmpdir(), 'golden-'));
const file = path.join(dir, 'ledger.jsonl');
fs.copyFileSync('golden-v1.jsonl', file);
const before = fs.readFileSync(file, 'utf8');
const out = execFileSync('node', ['bin/ledger.mjs', 'state'], {env: {...process.env, LEDGER_FILE: file}, encoding: 'utf8'});
const state = JSON.parse(out);
const expected = JSON.parse(fs.readFileSync('expected-state-v1.json', 'utf8'));
const norm = (o) => JSON.stringify(Object.fromEntries(Object.entries(o).sort()));
if (norm(state) !== norm(expected)) { console.error('v1 golden replay produced wrong state:', out); process.exit(1); }
if (fs.readFileSync(file, 'utf8') !== before) { console.error('replay modified the ledger file'); process.exit(1); }
console.log('GOLDEN_OK');

import {execFileSync, spawnSync} from 'node:child_process';
import fs from 'node:fs';
import os from 'node:os';
import path from 'node:path';
const dir = fs.mkdtempSync(path.join(os.tmpdir(), 'removed-'));
const file = path.join(dir, 'ledger.jsonl');
const env = {...process.env, LEDGER_FILE: file};
execFileSync('node', ['bin/ledger.mjs', 'add', 'x', '5'], {env});
execFileSync('node', ['bin/ledger.mjs', 'remove', 'x'], {env});
const refusal = spawnSync('node', ['bin/ledger.mjs', 'adjust', 'x', '2'], {env, encoding: 'utf8'});
if (refusal.status === 0) { console.error('adjust on a removed item must exit non-zero'); process.exit(1); }
if (!String(refusal.stderr || '').trim()) { console.error('adjust refusal must print to stderr'); process.exit(1); }
fs.appendFileSync(file, JSON.stringify({seq: '3', ts: '2026-03-08T00:00:00.000Z', type: 'adjust', name: 'ghost', delta: 3}) + '\n');
const state = JSON.parse(execFileSync('node', ['bin/ledger.mjs', 'state'], {env, encoding: 'utf8'}));
if (state.x !== undefined) { console.error('removed item x reappeared:', JSON.stringify(state)); process.exit(1); }
if (state.ghost !== undefined) { console.error('historical adjust-on-missing must replay as no-op:', JSON.stringify(state)); process.exit(1); }
console.log('REMOVED_OK');

import {execFileSync, spawnSync} from 'node:child_process';
import fs from 'node:fs';
import os from 'node:os';
import path from 'node:path';
const dir = fs.mkdtempSync(path.join(os.tmpdir(), 'undo-'));
const file = path.join(dir, 'ledger.jsonl');
const env = {...process.env, LEDGER_FILE: file};
execFileSync('node', ['bin/ledger.mjs', 'add', 'a', '5'], {env});
execFileSync('node', ['bin/ledger.mjs', 'adjust', 'a', '3'], {env});
let state = JSON.parse(execFileSync('node', ['bin/ledger.mjs', 'state'], {env, encoding: 'utf8'}));
if (state.a?.qty !== 8) { console.error('setup failed, expected a.qty=8, got', JSON.stringify(state)); process.exit(1); }
const before = fs.readFileSync(file, 'utf8');
execFileSync('node', ['bin/ledger.mjs', 'undo'], {env});
const after = fs.readFileSync(file, 'utf8');
if (!after.startsWith(before)) { console.error('undo rewrote or truncated the log'); process.exit(1); }
if (after.length <= before.length) { console.error('undo must append to the log'); process.exit(1); }
state = JSON.parse(execFileSync('node', ['bin/ledger.mjs', 'state'], {env, encoding: 'utf8'}));
if (state.a?.qty !== 5) { console.error('undo did not revert the adjust, state:', JSON.stringify(state)); process.exit(1); }
const history = execFileSync('node', ['bin/ledger.mjs', 'history'], {env, encoding: 'utf8'});
if (!/adjust/.test(history) || history.split('\n').filter(Boolean).length < 3) { console.error('history must keep showing original events plus the undo'); process.exit(1); }
const empty = spawnSync('node', ['bin/ledger.mjs', 'undo'], {env: {...process.env, LEDGER_FILE: path.join(dir, 'empty.jsonl')}, encoding: 'utf8'});
if (empty.status === 0) { console.error('undo with nothing to undo must exit non-zero'); process.exit(1); }
console.log('UNDO_OK');
